      { "name": "Inventory Service", "responsibility": "Reserves items against available stock. Compensation: releases the reservation.", "boundaries": "Owns the Inventory/StockReservation aggregate. Exposes ReserveItems and ReleaseReservation commands." },
      { "name": "Payment Service", "responsibility": "Charges the customer. Compensation: issues a refund.", "boundaries": "Owns the Payment/Transaction aggregate. Exposes ChargeCustomer and RefundPayment commands." },
      { "name": "Courier Service", "responsibility": "Assigns a courier to the order. Compensation: unassigns the courier.", "boundaries": "Owns the CourierAssignment aggregate. Exposes AssignCourier and UnassignCourier commands." },
      { "name": "Saga State Store", "responsibility": "Persists the current step, completed steps, and compensation log for each saga instance. Enables crash recovery.", "boundaries": "Durable storage (database table or dedicated store). The orchestrator is the sole writer." }
