      { "from": "Saga Orchestrator", "to": "Payment Service", "contract": "ChargeCustomer(orderId, customerId, amount) → {success, transactionId} | {failure, reason}; RefundPayment(transactionId) → {success} | {failure, reason}", "coupling_type": "command" },
      { "from": "Saga Orchestrator", "to": "Courier Service", "contract": "AssignCourier(orderId, pickupLocation, deliveryLocation) → {success, courierId} | {failure, reason}; UnassignCourier(orderId, courierId) → {success} | {failure, reason}", "coupling_type": "command" },
      { "from": "Saga Orchestrator", "to": "Saga State Store", "contract": "SaveState(sagaId, step, status, completedSteps[], compensationLog[]); LoadState(sagaId) → SagaState", "coupling_type": "direct (same process or dedicated DB)" }
