      { "upstream": "Saga Coordination", "downstream": "Order Management", "relationship": "Customer-Supplier: Saga Orchestrator drives Order Service via commands. Order Service owns its model and can reject commands." },
      { "upstream": "Saga Coordination", "downstream": "Inventory", "relationship": "Customer-Supplier" },
      { "upstream": "Saga Coordination", "downstream": "Payment", "relationship": "Customer-Supplier" },
      { "upstream": "Saga Coordination", "downstream": "Courier Assignment", "relationship": "Customer-Supplier" },
      { "upstream": "Order Management", "downstream": "Saga Coordination", "relationship": "Published Language: Order Service publishes orderId and status that the saga references, but the saga does not import Order domain objects — it works with IDs and status enums only." }
